args.sparql:
SELECT ?country
WHERE {
  ?championship wdt:P31 wd:Q653139;
                wdt:P585 ?champDate.
  ?championship wdt:P2723 ?event.
  ?event rdfs:label "Men's 4x400 metres relay"@en;
          p:P1195 ?resultStatement.
  ?resultStatement ps:P1195 ?result.
  ?resultStatement pq:P1546 wd:Q2.
  ?result wdt:P17 ?country.
  FILTER NOT EXISTS {
    ?otherChamp wdt:P31 wd:Q653139;
                wdt:P585 ?otherDate.
    FILTER (?otherDate > ?champDate)
  }
}
LIMIT 1

SELECT ?country
WHERE {
  ?champ wdt:P31 wd:Q29971422 ;
         wdt:P585 ?date.
  ?champ wdt:P1357 ?event .
  ?event rdfs:label 'Men\'s 4x400m relay'@en.
  ?event p:P1195 ?resultStatement .
  ?resultStatement ps:P1195 ?result .
  ?result wdt:P1546 wd:Q22852 .
  ?result wdt:P17 ?country .
  FILTER NOT EXISTS {
    ?otherChamp wdt:P31 wd:Q29971422 ;
                wdt:P585 ?otherDate .
    FILTER (?otherDate > ?date)
  }
}
ORDER BY DESC(?date)
LIMIT 1

